        long long max_val = nums.back();

        if (max_val <= min_val * k) {
            // This subarray is balanced, calculate the number of elements to remove
            long long remove_count = nums.size() - (i + 1);
            min_remove = std::min(min_remove, remove_count);
            break; // No need to check smaller subarrays
        }
    }

    return min_remove;
}
